if (project.name in publicModules) {
    configureAbiValidation()
    configureAndroidAbiValidation()
}

for (subproject in rootProject.subprojects) {
    if (subproject.name in publicModules) {
        api(subproject)
    }
}

if (painter == null && request.useExistingImageAsPlaceholder) {
    this.painter?.let { painter = it }
}

if (request.defined.precision == null) {
    // AsyncImagePainter scales the image to fit the canvas size at draw time.
    precision(Precision.INEXACT)
}

if (isPreview) {
    // The request must be executed synchronously in the preview environment.
    coroutineContext(EmptyCoroutineContext)
}

if (isDone) {
    start = null
} else {
    // Increment this value to force the painter to be redrawn.
    invalidateTick++
}

if (node.contentDescription != contentDescription) {
    node.contentDescription = contentDescription
    node.invalidateSemantics()
}

if (painter.intrinsicSize.isSpecified) {
    val modifiedConstraints = modifyConstraints(constraints)
    val layoutWidth = measurable.minIntrinsicWidth(height)
    max(modifiedConstraints.minWidth, layoutWidth)
} else {
    measurable.minIntrinsicWidth(height)
}

if (painter.intrinsicSize.isSpecified) {
    val modifiedConstraints = modifyConstraints(constraints)
    val layoutWidth = measurable.maxIntrinsicWidth(height)
    max(modifiedConstraints.minWidth, layoutWidth)
} else {
    measurable.maxIntrinsicWidth(height)
}

if (painter.intrinsicSize.isSpecified) {
    val modifiedConstraints = modifyConstraints(constraints)
    val layoutHeight = measurable.minIntrinsicHeight(width)
    max(modifiedConstraints.minHeight, layoutHeight)
} else {
    measurable.minIntrinsicHeight(width)
}

if (painter.intrinsicSize.isSpecified) {
    val modifiedConstraints = modifyConstraints(constraints)
    val layoutHeight = measurable.maxIntrinsicHeight(width)
    max(modifiedConstraints.minHeight, layoutHeight)
} else {
    measurable.maxIntrinsicHeight(width)
}

if (contentDescription != null) {
    this.contentDescription = contentDescription
    this.role = Role.Image
}

if (oldDispatcher is DeferredDispatchCoroutineDispatcher && oldDispatcher != newDispatcher) {
    oldDispatcher.unconfined = false
}

try {
    return super.read(sink, byteCount)
} catch (e: Exception) {
    exception = e
    throw e
}

if (packageName == context.packageName) {
    context.resources
} else {
    context.packageManager.getResourcesForApplication(packageName)
}

if (drawable is SizeProvider) {
    drawable.size
} else {
    // Estimate 4 bytes per pixel.
    4L * drawable.width * drawable.height
}

if (request.target is ViewTarget<*>) {
    return request.target.view.requestManager.getDisposable(job)
} else {
    return OneShotDisposable(job)
}

if (!target.view.isAttachedToWindow) {
    target.view.requestManager.setRequest(this)
    throw CancellationException("'ViewTarget.view' must be attached to a window.")
}

if (target is ViewTarget<*>) {
    val lifecycle = request.lifecycle ?: request.findLifecycle()
    return ViewTargetRequestDelegate(imageLoader, request, target, lifecycle, job)
}

if (request.defined.precision == null) {
    builder.precision(request.resolvePrecision(sizeResolver))
}

if (isAlive) {
    removeOnPreDrawListener(victim)
} else {
    view.viewTreeObserver.removeOnPreDrawListener(victim)
}

if (drawable is BitmapDrawable) {
    val bitmap = drawable.bitmap
    if (isConfigValid(bitmap, config) &&
        isSizeValid(allowInexactSize, bitmap, size, scale, maxSize)
    ) {
        return bitmap
    }
}

for (index in startIndex until fetcherFactories.size) {
    val (factory, type) = fetcherFactories[index]
    if (type.isInstance(data)) {
        val fetcher = (factory as Fetcher.Factory<Any>).create(data, options, imageLoader)
        if (fetcher != null) return fetcher to index
    }
}

for (index in startIndex until decoderFactories.size) {
    val factory = decoderFactories[index]
    val decoder = factory.create(result, options, imageLoader)
    if (decoder != null) return decoder to index
}

if (maxSize.height is Dimension.Pixels) {
    val maxHeightPercent = maxSize.height.px / srcHeight.toDouble()
    percent = percent.coerceAtMost(maxHeightPercent)
}

if (maxSize.width is Dimension.Pixels) {
    val maxWidthPercent = maxSize.width.px / srcWidth
    percent = percent.coerceAtMost(maxWidthPercent)
}

if (maxSize.height is Dimension.Pixels) {
    val maxHeightPercent = maxSize.height.px / srcHeight
    percent = percent.coerceAtMost(maxHeightPercent)
}

if (fileSystem.exists(journalFileBackup)) {
    // If journal file also exists just delete backup file.
    if (fileSystem.exists(journalFile)) {
        fileSystem.delete(journalFileBackup)
    } else {
        fileSystem.atomicMove(journalFileBackup, journalFile)
    }
}

if (fileSystem.exists(journalFile)) {
    fileSystem.atomicMove(journalFile, journalFileBackup)
    fileSystem.atomicMove(journalFileTmp, journalFile)
    fileSystem.delete(journalFileBackup)
} else {
    fileSystem.atomicMove(journalFileTmp, journalFile)
}

if (!fileSystem.exists(file)) {
    // Since the entry is no longer valid, remove it so the metadata is accurate
    // (i.e. the cache size).
    try {
        removeEntry(this)
    } catch (_: IOException) {}
    return null
}
